fixes.code:
let v = vec!["1", "2", "3"];
let nums = v.iter().map(|s| s.parse::<i32>().unwrap());
sum_iter(nums);

fn join_iter(iter: impl Iterator<Item = &'static str>) -> String {
    iter.collect::<Vec<_>>().join(", ")
}
